"use strict";(self.webpackChunkbo_bi_co_website=self.webpackChunkbo_bi_co_website||[]).push([["1705"],{1323(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/06/10/release","metadata":{"permalink":"/updates/2026/06/10/release","source":"@site/blog/updates/2026-06-10-release.mdx","title":"BoBiCo Shader 1.0 Release.","description":"After almost a month. We\'re so glad to introduce the 1.0 version of our BoBiCo shader in \\"my birthday\\". Our first release of the shader.","date":"2026-06-10T00:00:00.000Z","tags":[],"readingTime":1.18,"hasTruncateMarker":false,"authors":[{"name":"\u4E43\u3116\u4E43\u722A\u5342\u531A \xdc","title":"BoBiCo Shader Developer/Documentation Author","socials":{"github":"https://github.com/BobmacU","youtube":"https://youtube.com/@Bobmacjefferson"},"imageURL":"/img/authors/bobmac.png","key":"bobmac","page":null}],"frontMatter":{"title":"BoBiCo Shader 1.0 Release.","authors":["bobmac"]},"unlisted":false},"content":"After almost a month. We\'re so glad to introduce the **1.0** version of our **BoBiCo** shader in **\\"my birthday\\"**. Our first release of the shader.\\n**1.0** contains many features at the release. You can already make **fancy stylized characters** or go **PBR mode**. \\nOr even translate and port most of the features from **LilToon** and **MToon**! \\n\\nOur shader is now available on **S&box Workshop**, **Github** and **Gumroad**. Fully open-source in **MIT** license!\\n\\n### Features\\n- **6 shading modes + 1 Extra** : Flat, Multilayer shading, TextureRamp shading, Shademap Shading, Realistic Shading and Fur Shading. Extra as Wrap Shading for all modes.\\n- **3 rendering modes** : Opaque, Cutoff and Transparent with Dither Alpha, Alpha-to-Coverage and Fresnel Alpha features.\\n- **Full Lighting support** : Supports Direct + Indirect with dynamically adapting to the environment. Powered by our own Shading Model.\\n- **Customization** : Supports two slots for Main Color (2nd Color) with decal tools, Normal Map, Emission, Matcaps.\\nOKLab and HSV color space support with many color adjustment controls for maximum color control for many features.\\n- **Stylized features** : Matcaps, Inverted hull Outlines, Glitter and more.\\n- **PBR Support** : Get PBR support for all modes (except fur.) with advanced controls and multi-channel controls.\\n- **Advanced features** : SSAO, Parallax Occlusion, Fur, Self-shadowing and Subsurface Scattering.\\nAnd many many more..\\n\\n# [Download here!](/docs/general-info/download-and-usage)\\n\\nSee our **Documentation** for full detailed documentation about the features our shader offers!\\nThank you for using our shader :)\\n\\n---"}]}}')}}]);